import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import org.owasp.encoder.Encode;

public class XSSSecureCode {
    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        try (FileWriter fileWriter = new FileWriter(new File("output.html"))) {
            fileWriter.write("<html>");
            fileWriter.write("<head><title>Secure Page</title></head>");
            fileWriter.write("<body>");
            fileWriter.write("<h1>Welcome " + Encode.forHtml(userInput) + "</h1>"); // User input properly encoded
            fileWriter.write("</body>");
            fileWriter.write("</html>");

            System.out.println("Output written to output.html");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
